/// Executor for FileProcessing flow
pub struct FileProcessingFlowExecutor<H: FileProcessingStepHandler> {
    handler: Arc<H>,
}

impl<H: FileProcessingStepHandler> FileProcessingFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self { handler }
    }

    /// Start a new flow instance
    pub async fn start(&self, instance_id: impl Into<String>) -> Result<FileProcessingFlowInstance, FlowError> {
        let mut instance = FileProcessingFlowInstance::new(instance_id);
        instance.status = FileProcessingFlowStatus::Running;
        instance.current_step = Some(FileProcessingFlowStep::LoadJob);
        Ok(instance)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut FileProcessingFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            FileProcessingFlowStep::LoadJob => {
                self.handler.handle_load_job(instance).await?
            }
            FileProcessingFlowStep::MarkRunning => {
                self.handler.handle_mark_running(instance).await?
            }
            FileProcessingFlowStep::LoadFile => {
                self.handler.handle_load_file(instance).await?
            }
            FileProcessingFlowStep::LoadBucket => {
                self.handler.handle_load_bucket(instance).await?
            }
            FileProcessingFlowStep::RouteByJobType => {
                let next = self.handler.evaluate_route_by_job_type(instance).await?;
                Some(next)
            }
            FileProcessingFlowStep::ProcessImageThumbnail => {
                self.handler.handle_process_image_thumbnail(instance).await?
            }
            FileProcessingFlowStep::StoreImageThumbnail => {
                self.handler.handle_store_image_thumbnail(instance).await?
            }
            FileProcessingFlowStep::UpdateFileThumbnail => {
                self.handler.handle_update_file_thumbnail(instance).await?
            }
            FileProcessingFlowStep::ProcessVideoThumbnail => {
                self.handler.handle_process_video_thumbnail(instance).await?
            }
            FileProcessingFlowStep::StoreVideoThumbnail => {
                self.handler.handle_store_video_thumbnail(instance).await?
            }
            FileProcessingFlowStep::UpdateFileVideoThumbnail => {
                self.handler.handle_update_file_video_thumbnail(instance).await?
            }
            FileProcessingFlowStep::ProcessDocumentPreview => {
                self.handler.handle_process_document_preview(instance).await?
            }
            FileProcessingFlowStep::StoreDocumentPreview => {
                self.handler.handle_store_document_preview(instance).await?
            }
            FileProcessingFlowStep::UpdateFileDocumentPreview => {
                self.handler.handle_update_file_document_preview(instance).await?
            }
            FileProcessingFlowStep::ProcessCompression => {
                self.handler.handle_process_compression(instance).await?
            }
            FileProcessingFlowStep::StoreCompressedFile => {
                self.handler.handle_store_compressed_file(instance).await?
            }
            FileProcessingFlowStep::UpdateFileCompression => {
                self.handler.handle_update_file_compression(instance).await?
            }
            FileProcessingFlowStep::UpdateBucketCompressionStats => {
                self.handler.handle_update_bucket_compression_stats(instance).await?
            }
            FileProcessingFlowStep::ProcessVirusScan => {
                self.handler.handle_process_virus_scan(instance).await?
            }
            FileProcessingFlowStep::CheckThreatLevel => {
                let next = self.handler.evaluate_check_threat_level(instance).await?;
                Some(next)
            }
            FileProcessingFlowStep::UpdateScanSafe => {
                self.handler.handle_update_scan_safe(instance).await?
            }
            FileProcessingFlowStep::UpdateScanWarning => {
                self.handler.handle_update_scan_warning(instance).await?
            }
            FileProcessingFlowStep::NotifyScanWarning => {
                self.handler.handle_notify_scan_warning(instance).await?
            }
            FileProcessingFlowStep::UpdateScanThreat => {
                self.handler.handle_update_scan_threat(instance).await?
            }
            FileProcessingFlowStep::NotifyThreatDetected => {
                self.handler.handle_notify_threat_detected(instance).await?
            }
            FileProcessingFlowStep::ProcessDeduplication => {
                self.handler.handle_process_deduplication(instance).await?
            }
            FileProcessingFlowStep::CheckExistingHash => {
                self.handler.handle_check_existing_hash(instance).await?
            }
            FileProcessingFlowStep::UpdateExistingHash => {
                self.handler.handle_update_existing_hash(instance).await?
            }
            FileProcessingFlowStep::LinkFileHash => {
                self.handler.handle_link_file_hash(instance).await?
            }
            FileProcessingFlowStep::CreateNewHash => {
                self.handler.handle_create_new_hash(instance).await?
            }
            FileProcessingFlowStep::MarkComplete => {
                self.handler.handle_mark_complete(instance).await?
            }
            FileProcessingFlowStep::EmitCompleteEvent => {
                self.handler.handle_emit_complete_event(instance).await?
            }
            FileProcessingFlowStep::Complete => {
                self.handler.handle_complete(instance).await?;
                None // Terminal step
            }
            FileProcessingFlowStep::RetryOrFail => {
                let next = self.handler.evaluate_retry_or_fail(instance).await?;
                Some(next)
            }
            FileProcessingFlowStep::ScheduleRetry => {
                self.handler.handle_schedule_retry(instance).await?
            }
            FileProcessingFlowStep::RetryTerminal => {
                self.handler.handle_retry_terminal(instance).await?;
                None // Terminal step
            }
            FileProcessingFlowStep::MarkFailed => {
                self.handler.handle_mark_failed(instance).await?
            }
            FileProcessingFlowStep::EmitFailedEvent => {
                self.handler.handle_emit_failed_event(instance).await?
            }
            FileProcessingFlowStep::FailedTerminal => {
                self.handler.handle_failed_terminal(instance).await?;
                None // Terminal step
            }
            FileProcessingFlowStep::JobNotFound => {
                self.handler.handle_job_not_found(instance).await?;
                None // Terminal step
            }
            FileProcessingFlowStep::FileNotFound => {
                self.handler.handle_file_not_found(instance).await?;
                None // Terminal step
            }
            FileProcessingFlowStep::UnknownJobType => {
                self.handler.handle_unknown_job_type(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = FileProcessingFlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut FileProcessingFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != FileProcessingFlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut FileProcessingFlowInstance) {
        instance.status = FileProcessingFlowStatus::Cancelled;
        instance.updated_at = chrono::Utc::now();
    }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut FileProcessingFlowInstance, error: impl Into<String>) {
        instance.status = FileProcessingFlowStatus::Failed;
        instance.error = Some(error.into());
        instance.updated_at = chrono::Utc::now();
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = FileProcessingFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, FileProcessingFlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = FileProcessingFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = FileProcessingFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = FileProcessingFlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = FileProcessingFlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}
